import UIKit
import Alamofire
import SwiftyJSON

class TradeViewController: UIViewController {
    
    @IBOutlet weak var stockSymbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var priceLabel: UILabel!
    @IBOutlet weak var executeButton: UIButton!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        fetchStockPrice(symbol: "AAPL")
        setupUI()
    }
    
    func setupUI() {
        executeButton.layer.cornerRadius = 8
        executeButton.backgroundColor = .blue
        executeButton.setTitleColor(.white, for: .normal)
    }
    
    @IBAction func executeTrade(_ sender: UIButton) {
        guard let symbol = stockSymbolTextField.text,
              let quantityString = quantityTextField.text,
              let quantity = Int(quantityString),
              !symbol.isEmpty,
              quantity > 0 else {
            showAlert(title: "Invalid Input", message: "Please enter a valid stock symbol and quantity.")
            return
        }
        
        executeTrade(symbol: symbol, quantity: quantity)
    }
    
    func fetchStockPrice(symbol: String) {
        let url = "https://api.example.com/stock/\(symbol)"
        
        Alamofire.request(url, method: .get).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let json = JSON(value),
                   let price = json["price"].double {
                    DispatchQueue.main.async {
                        self.priceLabel.text = "Price: $\(String(format: "%.2f", price))"
                    }
                }
            case .failure(let error):
                print("Error fetching stock price: \(error)")
            }
        }
    }
    
    func executeTrade(symbol: String, quantity: Int) {
        let url = "https://api.example.com/trade"
        
        let parameters: [String: Any] = [
            "symbol": symbol,
            "quantity": quantity
        ]
        
        Alamofire.request(url, method: .post, parameters: parameters, encoding: JSONEncoding.default).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let json = JSON(value),
                   let status = json["status"].string,
                   status == "success" {
                    DispatchQueue.main.async {
                        self.showAlert(title: "Trade Executed", message: "Your trade has been executed successfully.")
                    }
                } else {
                    DispatchQueue.main.async {
                        self.showAlert(title: "Error", message: "Failed to execute trade.")
                    }
                }
            case .failure(let error):
                print("Error executing trade: \(error)")
                DispatchQueue.main.async {
                    self.showAlert(title: "Error", message: "Failed to execute trade.")
                }
            }
        }
    }
    
    func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default, handler: nil))
        present(alert, animated: true, completion: nil)
    }
}